import React, { useState } from 'react';
import { useQuery } from 'wasp/client/operations';
import { getTasks, getLabels, createTask, createLabel, addLabelToTask } from 'wasp/client/operations';

export function MainPage() {
  const { data: tasks, isLoading: isTasksLoading, error: tasksError } = useQuery(getTasks);
  const { data: labels, isLoading: isLabelsLoading, error: labelsError } = useQuery(getLabels);

  const [newTaskDesc, setNewTaskDesc] = useState('');
  const [newLabelName, setNewLabelName] = useState('');
  const [selectedLabels, setSelectedLabels] = useState<Record<number, number>>({});

  const handleCreateTask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskDesc) return;
    try {
      await createTask({ description: newTaskDesc });
      setNewTaskDesc('');
    } catch (err) {
      console.error(err);
    }
  };

  const handleCreateLabel = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newLabelName) return;
    try {
      await createLabel({ name: newLabelName });
      setNewLabelName('');
    } catch (err) {
      console.error(err);
    }
  };

  const handleAddLabel = async (taskId: number) => {
    const labelId = selectedLabels[taskId];
    if (!labelId) return;
    try {
      await addLabelToTask({ taskId, labelId });
    } catch (err) {
      console.error(err);
    }
  };

  if (isTasksLoading || isLabelsLoading) return <div>Loading...</div>;
  if (tasksError) return <div>Error loading tasks: {tasksError.message}</div>;
  if (labelsError) return <div>Error loading labels: {labelsError.message}</div>;

  return (
    <div style={{ padding: '20px' }}>
      <h1>Tasks and Labels</h1>

      <div style={{ marginBottom: '20px' }}>
        <h2>Create Task</h2>
        <form onSubmit={handleCreateTask}>
          <input 
            type="text" 
            value={newTaskDesc} 
            onChange={(e) => setNewTaskDesc(e.target.value)} 
            placeholder="Task description"
          />
          <button type="submit">Add Task</button>
        </form>
      </div>

      <div style={{ marginBottom: '20px' }}>
        <h2>Create Label</h2>
        <form onSubmit={handleCreateLabel}>
          <input 
            type="text" 
            value={newLabelName} 
            onChange={(e) => setNewLabelName(e.target.value)} 
            placeholder="Label name"
          />
          <button type="submit">Add Label</button>
        </form>
      </div>

      <div>
        <h2>Tasks</h2>
        <ul>
          {tasks?.map(task => (
            <li key={task.id} style={{ marginBottom: '10px', border: '1px solid #ccc', padding: '10px' }}>
              <div><strong>{task.description}</strong></div>
              <div>
                Labels: {task.labels.map(l => l.name).join(', ')}
              </div>
              <div style={{ marginTop: '5px' }}>
                <select 
                  value={selectedLabels[task.id] || ''}
                  onChange={(e) => setSelectedLabels({ ...selectedLabels, [task.id]: parseInt(e.target.value) })}
                  style={{ marginRight: '5px' }}
                >
                  <option value="" disabled>Select a label</option>
                  {labels?.map(label => (
                    <option key={label.id} value={label.id}>{label.name}</option>
                  ))}
                </select>
                <button onClick={() => handleAddLabel(task.id)}>Add Label</button>
              </div>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}

