import { Task, Label } from 'wasp/entities';
import { CreateTask, CreateLabel, AddLabelToTask } from 'wasp/server/operations';

export const createTask: CreateTask<{ description: string }, Task> = async (args, context) => {
  return context.entities.Task.create({
    data: {
      description: args.description,
    },
  });
};

export const createLabel: CreateLabel<{ name: string }, Label> = async (args, context) => {
  return context.entities.Label.create({
    data: {
      name: args.name,
    },
  });
};

export const addLabelToTask: AddLabelToTask<{ taskId: number; labelId: number }, Task> = async (args, context) => {
  return context.entities.Task.update({
    where: { id: args.taskId },
    data: {
      labels: {
        connect: { id: args.labelId },
      },
    },
    include: {
      labels: true,
    },
  });
};

